from dataclasses import dataclass


@dataclass
class Request:
    user_id: int
    is_admin: bool


USERS = {1: "owner", 2: "member"}
AUDIT_LOG = []


def require_admin(request: Request) -> None:
    if not request.is_admin:
        raise PermissionError("admin required")


def record_audit_event(actor_id: int, action: str, target_id: int) -> None:
    AUDIT_LOG.append({"actor_id": actor_id, "action": action, "target_id": target_id})


def delete_user(request: Request, target_user_id: int) -> dict[str, object]:
    require_admin(request)
    if target_user_id == request.user_id:
        raise ValueError("cannot delete yourself")
    removed = USERS.pop(target_user_id, None)
    if removed is not None:
        record_audit_event(request.user_id, "delete_user", target_user_id)
    return {"deleted": removed is not None}
